worksheets:
worksheet {
  title: "Verb TO BE – Affirmative & Negative (Mini Practice)"
  description: "Quick practice of the verb TO BE in affirmative and negative forms."

  matching {
    left:
    - "Yes, I am."
    - "No, he isn't."
    - "I am not tired."
    - "She is a student."
    right:
    - Short affirmative answer
    - Short negative answer
    - Negative sentence
    - Affirmative sentence
  }

  fillblank {
    text: "A: Are you hungry?\nB: No, I ____ hungry."
    answer: "am not"
  }

  fillblank {
    text: "Carlos ____ from Guatemala. He is from Mexico."
    answer: "isn't"
  }

  multiplechoice {
    question: "Choose the correct SHORT ANSWER."
    options:
    - Are you happy? → Yes, I'm.
    - Are you happy? → Yes, I am.
    - Are you happy? → Yes, am I.
    answer: "Are you happy? → Yes, I am."
  }

  multiplechoice {
    question: "Which sentence is CORRECT?"
    options:
    - She isn't a teacher.
    - She not is a teacher.
    - She is not teacher.
    answer: "She isn't a teacher."
  }
}

worksheet {
  title: "Verb Forms – 5 Main Forms (Verbs 51-66)"
  description: "Analiza y practica las 5 formas principales de los verbos: Base Form, Past Simple, Past Participle, 3rd Person Singular y Gerund."

  matching {
    left:
    - "Ask - Asked - Asked - Asks - Asking"
    - "Hear - Heard - Heard - Hears - Hearing"
    - "Sing - Sang - Sung - Sings - Singing"
    - "See - Saw - Seen - Sees - Seeing"
    - "Take - Took - Taken - Takes - Taking"
    - "Think - Thought - Thought - Thinks - Thinking"
    - "Swim - Swam - Swum - Swims - Swimming"
    right:
    - "Pedir, preguntar (regular)"
    - "Escuchar (irregular)"
    - "Cantar (irregular)"
    - "Ver (irregular)"
    - "Tomar (irregular)"
    - "Pensar (irregular)"
    - "Nadar (irregular)"
  }

  fillblank {
    text: "Ask → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Asked / Asked / Asking"
  }

  fillblank {
    text: "Hear → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Heard / Heard / Hearing"
  }

  fillblank {
    text: "Sing → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Sang / Sung / Singing"
  }

  fillblank {
    text: "Ride → Past Simple: ____ → Past Participle: ____ → 3rd Person: ____"
    answer: "Rode / Ridden / Rides"
  }

  fillblank {
    text: "Give → Past Simple: ____ → Past Participle: ____ → 3rd Person: ____"
    answer: "Gave / Given / Gives"
  }

  fillblank {
    text: "See → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Saw / Seen / Seeing"
  }

  fillblank {
    text: "Take → Past Simple: ____ → Past Participle: ____ → 3rd Person: ____"
    answer: "Took / Taken / Takes"
  }

  fillblank {
    text: "Think → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Thought / Thought / Thinking"
  }

  fillblank {
    text: "Find → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Found / Found / Finding"
  }

  fillblank {
    text: "Wash → Past Simple: ____ → Past Participle: ____ → 3rd Person: ____"
    answer: "Washed / Washed / Washes"
  }

  fillblank {
    text: "Have → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Had / Had / Having"
  }

  fillblank {
    text: "Get → Past Simple: ____ → Past Participle: ____ → Gerund: ____"
    answer: "Got / Got (Gotten) / Getting"
  }

  multiplechoice {
    question: "¿Cuál es la secuencia correcta de 'CANTAR'?"
    options:
    - Sing - Sang - Sung - Sings - Singing
    - Sing - Singed - Singed - Sings - Singing
    - Sing - Sung - Sang - Sings - Singing
    answer: "Sing - Sang - Sung - Sings - Singing"
  }

  multiplechoice {
    question: "¿Cuál es el Past Participle de 'RIDE'?"
    options:
    - Rode
    - Ridden
    - Rided
    answer: "Ridden"
  }

  multiplechoice {
    question: "¿Cuál es el Past Simple de 'SEE'?"
    options:
    - Seen
    - Saw
    - Seed
    answer: "Saw"
  }

  multiplechoice {
    question: "¿Cuál es el Gerund de 'USE'?"
    options:
    - Useing
    - Using
    - Used
    answer: "Using"
  }

  multiplechoice {
    question: "¿Cuál es la 3rd Person Singular de 'WASH'?"
    options:
    - Washs
    - Washes
    - Washies
    answer: "Washes"
  }

  multiplechoice {
    question: "¿Cuál es el Past Simple de 'THINK'?"
    options:
    - Thinked
    - Thank
    - Thought
    answer: "Thought"
  }

  multiplechoice {
    question: "¿Cuál es el Past Participle de 'GIVE'?"
    options:
    - Gave
    - Given
    - Gived
    answer: "Given"
  }

  multiplechoice {
    question: "¿Qué verbos son REGULARES de esta lista?"
    options:
    - Ask, Look, Wash
    - Sing, Ride, See
    - Get, Give, Take
    answer: "Ask, Look, Wash"
  }

  multiplechoice {
    question: "¿Cuál es el Gerund de 'GET'?"
    options:
    - Geting
    - Getting
    - Goting
    answer: "Getting"
  }

  multiplechoice {
    question: "¿Cuál es el Past Participle de 'LEARN'?"
    options:
    - Learned
    - Learnt
    - Ambas son correctas
    answer: "Ambas son correctas"
  }

  multiplechoice {
    question: "¿Cuál es la secuencia correcta de 'TOMAR'?"
    options:
    - Take - Took - Taken - Takes - Taking
    - Take - Taked - Taked - Takes - Taking
    - Take - Took - Took - Takes - Taking
    answer: "Take - Took - Taken - Takes - Taking"
  }

  multiplechoice {
    question: "¿Cuál es el Past Simple de 'HEAR'?"
    options:
    - Heared
    - Heard
    - Heart
    answer: "Heard"
  }

  textbox {
    prompt: "Elige 2 verbos de la lista (51-66) que NO hayas practicado aún y escribe sus 5 formas: Base Form, Past Simple, Past Participle, 3rd Person Singular y Gerund. Luego escribe su significado en español. Ejemplo: Learn - Learned - Learned - Learns - Learning = Aprender."
  }
}

worksheet {
  title: "Verb TO BE – Affirmative & Negative (A1)"
  description: "Practice the verb TO BE with questions, short answers, affirmative and negative forms. Topics: age, nationality, emotions, professions and personal characteristics."

  matching {
    left:
    - "Are you a teacher?"
    - "Is he from Guatemala?"
    - "I am not tired."
    - "She is a student."
    - "They aren't hungry."
    - "Yes, I am."
    - "No, he isn't."
    right:
    - Question with "you"
    - Question with "he"
    - Negative sentence with "I"
    - Affirmative sentence with "she"
    - Negative sentence with "they"
    - Short affirmative answer
    - Short negative answer
  }

  fillblank {
    text: "A: Are you a soccer fan?\nB: Yes, I ____."
    answer: "am"
  }

  fillblank {
    text: "A: Is she a doctor?\nB: No, she ____."
    answer: "isn't"
  }

  fillblank {
    text: "I ____ from Mexico. I'm from Guatemala."
    answer: "am not"
  }

  fillblank {
    text: "Carlos ____ tired. He worked all day."
    answer: "is"
  }

  fillblank {
    text: "They ____ at home. They are at school now."
    answer: "aren't"
  }

  fillblank {
    text: "A: Are you hungry?\nB: No, I ____ hungry. I ate ten minutes ago."
    answer: "am not"
  }

  fillblank {
    text: "She ____ a singer. She sings in a famous band."
    answer: "is"
  }

  fillblank {
    text: "We ____ good at math. We prefer English and science."
    answer: "aren't"
  }

  multiplechoice {
    question: "Choose the correct SHORT ANSWER."
    options:
    - Are you happy? → Yes, I'm.
    - Are you happy? → Yes, I am.
    - Are you happy? → Yes, am I.
    answer: "Are you happy? → Yes, I am."
  }

  multiplechoice {
    question: "Which question is CORRECT?"
    options:
    - Is he a student?
    - He is a student?
    - Is a student he?
    answer: "Is he a student?"
  }

  multiplechoice {
    question: "Choose the correct NEGATIVE sentence."
    options:
    - She isn't a teacher.
    - She not is a teacher.
    - She is not teacher.
    answer: "She isn't a teacher."
  }

  multiplechoice {
    question: "Read this: 'You are a doctor.' How do you CORRECT it if it's FALSE?"
    options:
    - No, I'm not a doctor. I'm a student.
    - No, I'm a doctor. I'm not a student.
    - No, I am not doctor. I am student.
    answer: "No, I'm not a doctor. I'm a student."
  }

  multiplechoice {
    question: "Maria is 12 years old. She is from Guatemala. She is good at sports. Which sentence is TRUE?"
    options:
    - Maria isn't from Guatemala.
    - Maria is good at sports.
    - Maria isn't 12 years old.
    answer: "Maria is good at sports."
  }

  reading {
    title: "New Friends"
    content:
    """
    Ana and Carlos are new friends. Ana is 13 years old. She is from Quetzaltenango. She is a student in seventh grade. She is happy today because she is good at English. She isn't tired. She isn't hungry.

    Carlos is 14 years old. He is from Guatemala City. He is a student too. He is a soccer fan. He isn't good at English, but he is good at math. He is tired today because he isn't at home. He is at school very early.
    """
    questions:
    - How old is Ana?
    - Is Ana from Guatemala City?
    - Why is Ana happy today?
    - Is Carlos good at English?
    - Why is Carlos tired today?
  }

  imagequestion {
    image: "https://images.unsplash.com/photo-1523050854058-8df90110d6c1?auto=format&fit=crop&w=900&q=80"
    prompt: "Look at this image of students in a classroom. Write 6 sentences: (1-2) affirmative sentences with 'is' or 'are', (3-4) negative sentences with 'isn't' or 'aren't', (5-6) two questions with 'Is...?' or 'Are...?' about the students in the picture."
  }

  textbox {
    prompt: "Write 6 sentences about yourself. Use the verb TO BE in affirmative and negative. Include: your age, your nationality, your profession (student), one emotion, one thing you are good at, and one thing you are not good at. Then write 2 questions you would ask a new friend."
  }

  speaking {
    prompt: "Interview a partner (real or imaginary). Ask 6 questions using 'Are you...?' (age, nationality, emotions, school, skills, physical state). Answer as your partner would. Then report 4 sentences about your partner using affirmative and negative forms. Example: 'Carlos is 13 years old. He isn't tired. He is a student. He isn't from Mexico.'"
  }
}

