worksheet {
  title: "Verb TO BE – Past Simple: Affirmative & Negative"
  description: "Practica la forma afirmativa (was/were) y negativa (wasn't/weren't) del verbo TO BE en pasado."

  matching {
    left:
    - "I was at home yesterday."
    - "She was a teacher before."
    - "They were happy with the result."
    - "He wasn't tired after the trip."
    - "We weren't in Guatemala City last week."
    - "You weren't late for class."
    right:
    - Afirmativo con "I"
    - Afirmativo con "she"
    - Afirmativo con "they"
    - Negativo con "he"
    - Negativo con "we"
    - Negativo con "you"
  }

  fillblank {
    text: "I ____ at the party on Saturday. (✓ afirmativo)"
    answer: "was"
  }

  fillblank {
    text: "They ____ happy with the result. (✗ negativo)"
    answer: "weren't"
  }

  fillblank {
    text: "You ____ very kind to help me. (✓ afirmativo)"
    answer: "were"
  }

  fillblank {
    text: "She ____ at school yesterday. It was a holiday. (✗ negativo)"
    answer: "wasn't"
  }

  multiplechoice {
    question: "¿Cuál es la forma NEGATIVA correcta de 'He was tired'?"
    options:
    - He wasn't tired.
    - He weren't tired.
    - He not was tired.
    answer: "He wasn't tired."
  }

  multiplechoice {
    question: "¿Cuál es la forma AFIRMATIVA correcta para 'ellos estaban felices'?"
    options:
    - They was happy.
    - They were happy.
    - They weren't happy.
    answer: "They were happy."
  }

  multiplechoice {
    question: "Completa: 'I ____ hungry, so I ate a sandwich.'"
    options:
    - was
    - were
    - wasn't
    answer: "was"
  }
}
